do local a,b=game:GetService'HttpService',{Folder='Luna_Hub',Ignore={},Options=Luna.Options}b.Parser={Toggle={Save=function(c,d)return{type='Toggle',name=c,value=d.Value}end,Load=function(c,d)if b.Options[c]then b.Options[c]:Set_Value(d.value)end end},Slider={Save=function(c,d)return{type='Slider',name=c,value=d.Value}end,Load=function(c,d)if b.Options[c]then b.Options[c]:Set_Value(d.value)end end},Dropdown={Save=function(c,d)return{type='Dropdown',name=c,value=d.Value,multi=d.Multi or false}end,Load=function(c,d)if b.Options[c]then b.Options[c]:Set_Value(d.value)end end},Colorpicker={Save=function(c,d)local e=d:GetValue()return{type='Colorpicker',name=c,r=e.Color.R,g=e.Color.G,b=e.Color.B,transparency=e.Transparency}end,Load=function(c,d)if b.Options[c]then b.Options[c]:SetValue{Color=Color3.new(d.r,d.g,d.b),Transparency=d.transparency}end end},Input={Save=function(c,d)return{type='Input',name=c,value=d.Value}end,Load=function(c,d)if b.Options[c]then b.Options[c]:Set_Value(d.value)end end}}function b.BuildFolder(c)local d,e=pcall(function()if not isfolder(c.Folder)then makefolder(c.Folder)end if not isfolder(c.Folder..'/Configs')then makefolder(c.Folder..'/Configs')end end)if not d then warn('Failed to create folder: '..tostring(e))end end function b.SetFolder(c,d)c.Folder=d c:BuildFolder()end function b.IgnoreOptions(c,d)for e,f in ipairs(d)do c.Ignore[f]=true end end function b.Save(c,d)if not d then return false,'No config name provided'end c:BuildFolder()local e={options={},savedAt=os.date'%Y-%m-%d %H:%M:%S'}for f,g in pairs(c.Options)do if type(g)=='table'and g.Value~=nil then if not c.Ignore[f]and c.Parser[g.Type]then local h=c.Parser[g.Type].Save(f,g)if h then table.insert(e.options,h)end end end end local f,g,h=c.Folder..'/Configs/'..d..'.json',pcall(a.JSONEncode,a,e)if not g then return false,'Failed to encode data'end local i,j=pcall(writefile,f,h)if not i then return false,'Failed to write file: '..tostring(j)end return true,'Config saved successfully'end function b.Load(c,d)if not d then return false,'No config name provided'end local e=c.Folder..'/Configs/'..d..'.json'if not isfile(e)then return false,'Config file not found'end local f,g=pcall(readfile,e)if not f then return false,'Failed to read file'end local h,i=pcall(a.JSONDecode,a,g)if not h then return false,'Failed to decode config data'end for j,k in ipairs(i.options)do if c.Parser[k.type]and not c.Ignore[k.name]then task.spawn(function()c.Parser[k.type].Load(k.name,k)end)end end return true,'Config loaded successfully'end function b.Delete(c,d)local e=c.Folder..'/Configs/'..d..'.json'if isfile(e)then delfile(e)return true,'Config deleted'end return false,'Config not found'end function b.ListConfigs(c)local d,e={},c.Folder..'/Configs/'if not isfolder(e)then return d end local f=listfiles(e)for g,h in ipairs(f)do if h:sub(-5)=='.json'then local i=h:match'([^/\\]+)%.json$'if i then table.insert(d,i)end end end return d end function b.EnableAutoSave(c,d,e)e=e or 1 local f for g,h in pairs(c.Options)do if type(h)=='table'and h.Value~=nil then local i=h.Callback h.Callback=function(j)if i then i(j)end if f then task.cancel(f)end f=task.delay(e,function()c:Save(d)print('Auto-saved config:',d)f=nil end)end end end end function b.CreateUI(c,d)local e,f=d:Create_Section{Title='Config Manager',Icon='rbxassetid://10734934585'},d:Create_Input('config_name',{Title='Config Name',Default='',Placeholder='Enter config name...',Numeric=false,Finished=false})d:Create_Button{Title='\u{1f4be} Save Config',Callback=function()local g=f:GetValue()if g==''then Luna:Notify{Title='Save Manager',Content='Please enter a config name!'}return end local h,i=c:Save(g)if h then Luna:Notify{Title='Save Manager',Content="Config '"..g.."' saved!"}if configDropdown then configDropdown:Set_Value(c:ListConfigs())end else Luna:Notify{Title='Save Manager',Content='Failed to save: '..i}end end}local g=d:Create_Dropdown('config_list',{Title='Config List',Options=c:ListConfigs(),Default=nil,Search=true,Multi=false})d:Create_Button{Title='\u{1f4c2} Load Config',Callback=function()local h=g:GetValue()if not h then Luna:Notify{Title='Save Manager',Content='Please select a config to load!'}return end local i,j=c:Load(h)if i then Luna:Notify{Title='Save Manager',Content="Config '"..h.."' loaded!"}else Luna:Notify{Title='Save Manager',Content='Failed to load: '..j}end end}d:Create_Button{Title='\u{1f5d1}\u{fe0f} Delete Config',Callback=function()local h=g:GetValue()if not h then Luna:Notify{Title='Save Manager',Content='Please select a config to delete!'}return end local i,j=c:Delete(h)if i then g:Set_Value(c:ListConfigs())Luna:Notify{Title='Save Manager',Content="Config '"..h.."' deleted!"}else Luna:Notify{Title='Save Manager',Content='Failed to delete: '..j}end end}d:Create_Button{Title='\u{1f504} Refresh List',Callback=function()g:Set_Value(c:ListConfigs())Luna:Notify{Title='Save Manager',Content='Config list refreshed!'}end}end function b.AutoLoad(c,d)local e,f=c:Load(d)if e then print('[Luna] Auto-loaded config:',d)else print('[Luna] No auto-load config found:',f)end return e end Luna.SaveManager=b end
